// Compose full AI prompt by merging base + enabled feature fragments
const user = $('Get User Profile').item.json;
const todayLog = $('Get Today Log').item.json;
const sevenDayLogs = $('Get 7-Day Trend').all().map(i => i.json);
const lastRec = $('Get Last Recommendation').item.json;
const systemPromptRaw = $('Read System Prompt').item.json.data || $('Read System Prompt').item.json;
const baseAnalysisRaw = $('Read Base Analysis Prompt').item.json.data || $('Read Base Analysis Prompt').item.json;
const registryRaw = $('Read Feature Registry').item.json;

const systemPrompt = typeof systemPromptRaw === 'string' ? systemPromptRaw : JSON.stringify(systemPromptRaw);
let baseAnalysis = typeof baseAnalysisRaw === 'string' ? baseAnalysisRaw : JSON.stringify(baseAnalysisRaw);
const registry = typeof registryRaw === 'string' ? JSON.parse(registryRaw) : registryRaw;

// Build 7-day summary text
const sevenDaySummary = sevenDayLogs.map(d => {
  const workoutIcon = d.workout_done ? '✅' : '❌';
  return `  ${d.log_date}: ${d.calories_consumed || 0} kcal | Sleep ${d.sleep_hours || '?'}h | Energy ${d.energy_level || '?'}/10 | Workout ${workoutIcon} | Steps ${d.steps || 0}`;
}).join('\n') || 'No previous data yet.';

const lastRecSummary = lastRec
  ? `Nutrition: ${(lastRec.nutrition_plan || '').substring(0, 200)}...\nWorkout: ${(lastRec.workout_plan || '').substring(0, 200)}...`
  : 'No previous recommendation — this is the first check-in.';

// Substitute base prompt variables
const substitutions = {
  '{name}': user.first_name || 'Friend',
  '{age}': user.age || 'Unknown',
  '{gender}': user.gender || 'Unknown',
  '{weight_kg}': user.weight_kg || 'Unknown',
  '{height_cm}': user.height_cm || 'Unknown',
  '{goal}': user.goal || 'maintenance',
  '{daily_calorie_target}': user.daily_calorie_target || 2000,
  '{activity_level}': user.activity_level || 'moderate',
  '{log_date}': todayLog.log_date || new Date().toISOString().split('T')[0],
  '{sleep_hours}': todayLog.sleep_hours || 0,
  '{energy_level}': todayLog.energy_level || 5,
  '{mood}': todayLog.mood || 'okay',
  '{food_description}': todayLog.food_description || 'Not provided',
  '{calories_consumed}': todayLog.calories_consumed || 0,
  '{protein_g}': todayLog.protein_g || 0,
  '{carbs_g}': todayLog.carbs_g || 0,
  '{fat_g}': todayLog.fat_g || 0,
  '{workout_description}': todayLog.workout_description || 'Rest day',
  '{steps}': todayLog.steps || 0,
  '{water_ml}': todayLog.water_ml || 0,
  '{seven_day_summary}': sevenDaySummary,
  '{last_recommendation_summary}': lastRecSummary
};

for (const [key, val] of Object.entries(substitutions)) {
  baseAnalysis = baseAnalysis.split(key).join(String(val));
}

// Append enabled feature prompt fragments
const enabledFeatures = (registry.features || []).filter(f => f.enabled && f.prompt_fragment);
let fragmentsToLoad = [];
for (const feature of enabledFeatures) {
  fragmentsToLoad.push({
    featureId: feature.id,
    fragmentPath: feature.prompt_fragment
  });
}

// Return data needed for next node (fragment loading)
return [{ json: {
  systemPrompt,
  userPrompt: baseAnalysis,
  fragmentsToLoad,
  enabledFeatures: enabledFeatures.map(f => f.id),
  telegramId: user.telegram_id,
  userId: user.id,
  userName: user.first_name
} }];

// Load each feature's prompt fragment and append to user prompt
// In production, each fragment is fetched via HTTP; here we read inline
const { systemPrompt, userPrompt, fragmentsToLoad, enabledFeatures, telegramId, userId, userName } = $json;

// Build combined prompt with all feature fragments appended
let combinedPrompt = userPrompt;

// Fragment content is appended; in production this node iterates HTTP calls
// The actual file reads happen via HTTP Request nodes in the feature loop
// For the engine to work standalone, we include a fallback that reads known fragments
const fragmentPaths = {
  'food_image_analysis': '/home/node/fitbuddy/config/prompts/feature-food-image.txt',
  'supplement_advisor':  '/home/node/fitbuddy/config/prompts/feature-supplements.txt',
  'restaurant_finder':   '/home/node/fitbuddy/config/prompts/feature-restaurants.txt',
  'mindset_coach':       '/home/node/fitbuddy/config/prompts/feature-mindset.txt'
};

// Fragments will be fetched in the HTTP loop nodes that follow
// Pass the data forward
return [{ json: {
  systemPrompt,
  userPrompt: combinedPrompt,
  fragmentsToLoad,
  enabledFeatures,
  telegramId,
  userId,
  userName,
  fragmentPaths
} }];

// Final prompt assembly before AI call
const data = $json;

// Any fragment content that was loaded gets appended here
// The system reads feature registry at runtime — new features auto-appear
const finalSystemPrompt = data.systemPrompt;
const finalUserPrompt = data.userPrompt + '\n\n' +
  '---\n' +
  'Provide a thorough, specific response covering ALL sections above. ' +
  'Format each section header exactly as shown with its emoji. ' +
  'Keep total response under 3500 characters for Telegram.';

return [{ json: {
  systemPrompt: finalSystemPrompt,
  userPrompt: finalUserPrompt,
  telegramId: data.telegramId,
  userId: data.userId,
  userName: data.userName,
  enabledFeatures: data.enabledFeatures
} }];

// Parse GPT response into structured sections
const aiResponse = $json.message?.content || $json.choices?.[0]?.message?.content || '';

// Split on emoji section headers
const sectionMarkers = [
  { key: 'nutrition_plan',      marker: '🍽️' },
  { key: 'workout_plan',        marker: '🏋️' },
  { key: 'substitutes',         marker: '🔄' },
  { key: 'progress_snapshot',   marker: '📈' },
  { key: 'motivational_message',marker: '💬' },
  { key: 'supplement_advice',   marker: '💊' },
  { key: 'restaurant_advice',   marker: '🍴' },
  { key: 'mindset_coaching',    marker: '🧠' },
  { key: 'food_photo_insight',  marker: '📸' }
];

const sections = {};
let remaining = aiResponse;

for (let i = 0; i < sectionMarkers.length; i++) {
  const { key, marker } = sectionMarkers[i];
  const nextMarkers = sectionMarkers.slice(i + 1).map(m => m.marker);

  const startIdx = remaining.indexOf(marker);
  if (startIdx === -1) continue;

  let endIdx = remaining.length;
  for (const nextMarker of nextMarkers) {
    const nextIdx = remaining.indexOf(nextMarker, startIdx + 1);
    if (nextIdx !== -1 && nextIdx < endIdx) {
      endIdx = nextIdx;
    }
  }

  sections[key] = remaining.substring(startIdx, endIdx).trim();
}

// Feature sections as JSONB
const featureSections = {};
const featureKeys = ['supplement_advice', 'restaurant_advice', 'mindset_coaching', 'food_photo_insight'];
for (const key of featureKeys) {
  if (sections[key]) featureSections[key] = sections[key];
}

const prevData = $('Finalize Prompt').item.json;

return [{ json: {
  fullResponse: aiResponse,
  nutritionPlan: sections.nutrition_plan || '',
  workoutPlan: sections.workout_plan || '',
  substitutes: sections.substitutes || '',
  progressSnapshot: sections.progress_snapshot || '',
  motivationalMessage: sections.motivational_message || '',
  featureSections,
  telegramId: prevData.telegramId,
  userId: prevData.userId,
  userName: prevData.userName,
  enabledFeatures: prevData.enabledFeatures
} }];

// Build dynamic action keyboard from enabled features
const enabledFeatures = $('Parse AI Response').item.json.enabledFeatures || [];

const featureButtons = {
  food_image_analysis: { text: '📸 Analyze Food Photo', callback_data: '/analyze' },
  supplement_advisor:  { text: '💊 Supplement Advice',  callback_data: '/supplements' },
  restaurant_finder:   { text: '🍴 Find Restaurants',   callback_data: '/restaurants' },
  challenge_system:    { text: '🏆 Challenges',          callback_data: '/challenges' },
  mindset_coach:       { text: '🧠 Mindset Coach',       callback_data: '/mindset' }
};

const keyboard = [];
for (const featureId of enabledFeatures) {
  if (featureButtons[featureId]) {
    keyboard.push([featureButtons[featureId]]);
  }
}

keyboard.push([{ text: '📊 Weekly Progress', callback_data: '/progress' }]);

return [{ json: {
  replyMarkup: JSON.stringify({ inline_keyboard: keyboard }),
  telegramId: $('Parse AI Response').item.json.telegramId
} }];

